// L (D13) + активность UART: всплески Serial в фазе с L дают TX (и частично RX при ответе ПК).
// Светодиод ON — питание, скетчем не управляется.

void setup() {
  pinMode(LED_BUILTIN, OUTPUT);
  Serial.begin(115200);
}

static void uartBurst() {
  // Много переключений линии TX — ярче мигает TX у многих клонов.
  for (uint16_t i = 0; i < 400; i++) {
    Serial.write((uint8_t)((i & 1) ? 0xFF : 0x00));
  }
  Serial.flush();
}

void loop() {
  digitalWrite(LED_BUILTIN, HIGH);
  uartBurst();
  delay(280);

  digitalWrite(LED_BUILTIN, LOW);
  // Короткий приём: если с ПК что-то пришло (монитор), RX мигнёт в этой фазе.
  uint32_t t0 = millis();
  while (millis() - t0 < 120) {
    while (Serial.available()) {
      (void)Serial.read();
    }
  }
  delay(280);
}

// Писк с платы:
// 1) По умолчанию — tone() на D13 (L). На части клонов слышно очень тихое «цок»/писк из-за светодиода/разводки.
// 2) Громко и нормально — пассивный buzzer между D8 и GND, ниже раскомментируй USE_BUZZER_8.

// #define USE_BUZZER_8
#ifdef USE_BUZZER_8
const uint8_t kPin = 8;
#else
const uint8_t kPin = LED_BUILTIN;  // 13
#endif

void setup() {
  pinMode(kPin, OUTPUT);
}

void loop() {
  tone(kPin, 2600, 160);
  delay(200);
  tone(kPin, 1900, 160);
  delay(200);
  tone(kPin, 3200, 200);
  delay(350);
}

/*
 * Колёсная платформа: 4 мини-мотора как два борта (левый / правый), два L298N или аналог.
 * Управление с телефона по Bluetooth (HC-05/HC-06, SPP): Android — «Serial Bluetooth Terminal»
 * или любой UART-терминал к сопряжённому модулю.
 *
 * Проводка HC-05: VCC 5V, GND, TX модуля -> D10 (RX SoftSerial), RX модуля <- D11 (TX) через делитель 1k/2k на 3.3V если модуль 3.3V RX.
 * L298N «левая пара» моторов на выход A: ENA->D5, IN1->D2, IN2->D4
 * L298N «правая пара» на выход B: ENB->D6, IN3->D7, IN4->D8
 * Объедини два левых мотора параллельно на один канал (ток!), то же справа. Питание моторов отдельное, общая земля с Arduino.
 */

#include <SoftwareSerial.h>

// --- Bluetooth (не использовать D0/D1 — там USB) ---
constexpr uint8_t BT_RX_PIN = 10;  // к TX модуля HC-05
constexpr uint8_t BT_TX_PIN = 11;  // к RX модуля (через резисторы при 3.3V RX)
SoftwareSerial BTSerial(BT_RX_PIN, BT_TX_PIN);

// --- Левый борт (один ШИМ + два направления) ---
constexpr uint8_t LEFT_PWM = 5;
constexpr uint8_t LEFT_IN1 = 2;
constexpr uint8_t LEFT_IN2 = 4;

// --- Правый борт ---
constexpr uint8_t RIGHT_PWM = 6;
constexpr uint8_t RIGHT_IN1 = 7;
constexpr uint8_t RIGHT_IN2 = 8;

constexpr uint32_t BT_BAUD = 9600;

static void motorChannel(uint8_t pwmPin, uint8_t in1, uint8_t in2, int speed) {
  speed = constrain(speed, -255, 255);
  if (speed > 0) {
    digitalWrite(in1, HIGH);
    digitalWrite(in2, LOW);
    analogWrite(pwmPin, (uint8_t)speed);
  } else if (speed < 0) {
    digitalWrite(in1, LOW);
    digitalWrite(in2, HIGH);
    analogWrite(pwmPin, (uint8_t)(-speed));
  } else {
    digitalWrite(in1, LOW);
    digitalWrite(in2, LOW);
    analogWrite(pwmPin, 0);
  }
}

static void drive(int left, int right) {
  motorChannel(LEFT_PWM, LEFT_IN1, LEFT_IN2, left);
  motorChannel(RIGHT_PWM, RIGHT_IN1, RIGHT_IN2, right);
}

static void stopAll() { drive(0, 0); }

void setup() {
  pinMode(LEFT_IN1, OUTPUT);
  pinMode(LEFT_IN2, OUTPUT);
  pinMode(RIGHT_IN1, OUTPUT);
  pinMode(RIGHT_IN2, OUTPUT);
  pinMode(LEFT_PWM, OUTPUT);
  pinMode(RIGHT_PWM, OUTPUT);
  stopAll();

  Serial.begin(115200);
  BTSerial.begin(BT_BAUD);

  Serial.println(F("wheel_platform: USB ok"));
  BTSerial.println(F("OK: M L R | F v | B v | T thr turn | S"));
}

void loop() {
  if (BTSerial.available()) {
    String line = BTSerial.readStringUntil('\n');
    line.trim();
    if (line.length() == 0) {
      return;
    }
    for (size_t i = 0; i < line.length(); i++) {
      line[i] = toupper(line[i]);
    }

    char cmd[8] = {0};
    int a = 0, b = 0;
    int n = sscanf(line.c_str(), "%7s %d %d", cmd, &a, &b);

    if (strcmp(cmd, "S") == 0 || strcmp(cmd, "STOP") == 0) {
      stopAll();
    } else if (strcmp(cmd, "M") == 0 && n == 3) {
      drive(constrain(a, -255, 255), constrain(b, -255, 255));
    } else if ((strcmp(cmd, "F") == 0 || strcmp(cmd, "B") == 0) && n >= 2) {
      int v = constrain(a, 0, 255);
      if (cmd[0] == 'F') {
        drive(v, v);
      } else {
        drive(-v, -v);
      }
    } else if (strcmp(cmd, "T") == 0 && n == 3) {
      int thr = constrain(a, -255, 255);
      int turn = constrain(b, -255, 255);
      int left = constrain(thr + turn, -255, 255);
      int right = constrain(thr - turn, -255, 255);
      drive(left, right);
    } else {
      BTSerial.println(F("ERR: S | M L R | F v | B v | T thr turn"));
    }
  }
}

