// L (D13) + всплески UART в фазе с L → TX; RX при приёме с ПК (монитор).
// ON (питание) скетчем не управляется.

void setup() {
  pinMode(LED_BUILTIN, OUTPUT);
  Serial.begin(115200);
}

static void uartBurst() {
  for (uint16_t i = 0; i < 400; i++) {
    Serial.write((uint8_t)((i & 1) ? 0xFF : 0x00));
  }
  Serial.flush();
}

void loop() {
  digitalWrite(LED_BUILTIN, HIGH);
  uartBurst();
  delay(280);

  digitalWrite(LED_BUILTIN, LOW);
  uint32_t t0 = millis();
  while (millis() - t0 < 120) {
    while (Serial.available()) {
      (void)Serial.read();
    }
  }
  delay(280);
}

// L (D13) + TX/RX на плате Uno (CH340):
// — L напрямую с GPIO 13.
// — TX/RX — это индикация обмена по линии USB↔ATmega (не отдельные «лампочки на пине»).
// Раньше был один короткий uartBurst (~30–40 мс при 115200), а L держался HIGH ~280 мс —
// на фото TX гас раньше, чем L. Теперь передача растянута на всё время, пока L включён.

constexpr uint32_t kPhaseMs = 300;

void setup() {
  pinMode(LED_BUILTIN, OUTPUT);
  Serial.begin(115200);
}

void loop() {
  // Фаза ON: L горит всё время; порции байт с паузой — TX активен столько же, сколько L.
  digitalWrite(LED_BUILTIN, HIGH);
  {
    uint32_t t0 = millis();
    while (millis() - t0 < kPhaseMs) {
      Serial.write(0xFF);
      Serial.write(0x00);
      delay(18);
    }
  }
  Serial.flush();

  // Фаза OFF: L погашен столько же; RX только если ПК что-то шлёт (монитор порта).
  digitalWrite(LED_BUILTIN, LOW);
  {
    uint32_t t0 = millis();
    while (millis() - t0 < kPhaseMs) {
      while (Serial.available()) {
        (void)Serial.read();
      }
      delay(5);
    }
  }
}

/**
 * XIAO ESP32-S3 Sense: камера OV2640/OV3660 + простой веб-снимок.
 *
 * После прошивки плата поднимает Wi-Fi точку доступа:
 *   SSID:     XIAO-CAM
 *   Пароль:  12345678
 * В браузере (телефон/ПК, подключённые к этой сети):
 *   http://192.168.4.1/         — страница с картинкой
 *   http://192.168.4.1/capture  — один кадр JPEG
 *
 * В Arduino IDE 2: плата «XIAO_ESP32S3», PSRAM «OPI» (для Sense), порт USB.
 */

#include <Arduino.h>
#include "esp_camera.h"
#include <WiFi.h>
#include <WebServer.h>

// --- Wi-Fi AP (без домашнего роутера) ---
static const char *kApSsid = "XIAO-CAM";
static const char *kApPass = "12345678";

WebServer server(80);

// Пины как в esp32 core: libraries/ESP32/examples/Camera/CameraWebServer/camera_pins.h (CAMERA_MODEL_XIAO_ESP32S3)
#define PWDN_GPIO_NUM -1
#define RESET_GPIO_NUM -1
#define XCLK_GPIO_NUM 10
#define SIOD_GPIO_NUM 40
#define SIOC_GPIO_NUM 39
#define Y9_GPIO_NUM 48
#define Y8_GPIO_NUM 11
#define Y7_GPIO_NUM 12
#define Y6_GPIO_NUM 14
#define Y5_GPIO_NUM 16
#define Y4_GPIO_NUM 18
#define Y3_GPIO_NUM 17
#define Y2_GPIO_NUM 15
#define VSYNC_GPIO_NUM 38
#define HREF_GPIO_NUM 47
#define PCLK_GPIO_NUM 13

static bool initCamera() {
  camera_config_t config;
  config.ledc_channel = LEDC_CHANNEL_0;
  config.ledc_timer = LEDC_TIMER_0;
  config.pin_d0 = Y2_GPIO_NUM;
  config.pin_d1 = Y3_GPIO_NUM;
  config.pin_d2 = Y4_GPIO_NUM;
  config.pin_d3 = Y5_GPIO_NUM;
  config.pin_d4 = Y6_GPIO_NUM;
  config.pin_d5 = Y7_GPIO_NUM;
  config.pin_d6 = Y8_GPIO_NUM;
  config.pin_d7 = Y9_GPIO_NUM;
  config.pin_xclk = XCLK_GPIO_NUM;
  config.pin_pclk = PCLK_GPIO_NUM;
  config.pin_vsync = VSYNC_GPIO_NUM;
  config.pin_href = HREF_GPIO_NUM;
  config.pin_sccb_sda = SIOD_GPIO_NUM;
  config.pin_sccb_scl = SIOC_GPIO_NUM;
  config.pin_pwdn = PWDN_GPIO_NUM;
  config.pin_reset = RESET_GPIO_NUM;
  config.xclk_freq_hz = 20000000;
  config.frame_size = FRAMESIZE_UXGA;
  config.pixel_format = PIXFORMAT_JPEG;
  config.grab_mode = CAMERA_GRAB_WHEN_EMPTY;
  config.fb_location = CAMERA_FB_IN_PSRAM;
  config.jpeg_quality = 12;
  config.fb_count = 1;

  if (config.pixel_format == PIXFORMAT_JPEG) {
    if (psramFound()) {
      config.jpeg_quality = 10;
      config.fb_count = 2;
      config.grab_mode = CAMERA_GRAB_LATEST;
    } else {
      config.frame_size = FRAMESIZE_SVGA;
      config.fb_location = CAMERA_FB_IN_DRAM;
    }
  }

  esp_err_t err = esp_camera_init(&config);
  if (err != ESP_OK) {
    Serial.printf("Camera init failed 0x%x\n", err);
    return false;
  }

  sensor_t *s = esp_camera_sensor_get();
  if (s->id.PID == OV3660_PID) {
    s->set_vflip(s, 1);
    s->set_brightness(s, 1);
    s->set_saturation(s, -2);
  }
  if (config.pixel_format == PIXFORMAT_JPEG) {
    s->set_framesize(s, FRAMESIZE_VGA);
  }
  return true;
}

static void handleRoot() {
  static const char html[] PROGMEM = R"rawliteral(
<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width">
<title>XIAO CAM</title></head><body>
<h3>XIAO ESP32-S3 Sense</h3>
<p><img src="/capture" style="max-width:100%;height:auto;border:1px solid #ccc"></p>
<p><a href="/capture">JPEG /capture</a></p>
</body></html>
)rawliteral";
  server.send_P(200, "text/html; charset=utf-8", html);
}

static void handleCapture() {
  camera_fb_t *fb = esp_camera_fb_get();
  if (!fb) {
    server.send(500, "text/plain", "capture failed");
    return;
  }
  WiFiClient client = server.client();
  if (!client.connected()) {
    esp_camera_fb_return(fb);
    return;
  }
  client.println(F("HTTP/1.1 200 OK"));
  client.println(F("Content-Type: image/jpeg"));
  client.println(F("Connection: close"));
  client.println();
  client.write(fb->buf, fb->len);
  esp_camera_fb_return(fb);
}

void setup() {
  Serial.begin(115200);
  delay(800);

  if (!initCamera()) {
    Serial.println("Camera not ready — проверь Sense-плату, PSRAM=OPI в настройках платы, антенну.");
    return;
  }
  Serial.println("Camera OK");

  WiFi.mode(WIFI_AP);
  if (!WiFi.softAP(kApSsid, kApPass)) {
    Serial.println("softAP failed");
    return;
  }
  Serial.print("AP SSID: ");
  Serial.println(kApSsid);
  Serial.print("AP IP: ");
  Serial.println(WiFi.softAPIP());  // обычно 192.168.4.1

  server.on("/", HTTP_GET, handleRoot);
  server.on("/capture", HTTP_GET, handleCapture);
  server.begin();
  Serial.println("HTTP server started");
}

void loop() {
  server.handleClient();
}

