/**
 * XIAO ESP32-S3 Sense: камера + MJPEG / веб-снимок через домашний Wi-Fi (STA).
 *
 * Подключение к роутеру (2.4 ГГц). После загрузки смотри IP в Serial Monitor
 * или на главной странице: http://<IP>/
 *
 * В Arduino IDE 2: плата «XIAO_ESP32S3», PSRAM «OPI» (Sense), порт USB.
 */

#include <Arduino.h>
#include "esp_camera.h"
#include <WiFi.h>
#include <WebServer.h>

// --- Wi-Fi STA (домашняя сеть) ---
// Имя сети как на роутере; «2.4» — только подсказка по диапазону, не часть SSID.
static const char *kWifiSsid = "дуангдихауз 2";
static const char *kWifiPass = "0815350698";

static constexpr uint32_t kWifiTimeoutMs = 90000;

WebServer server(80);

#define PWDN_GPIO_NUM -1
#define RESET_GPIO_NUM -1
#define XCLK_GPIO_NUM 10
#define SIOD_GPIO_NUM 40
#define SIOC_GPIO_NUM 39
#define Y9_GPIO_NUM 48
#define Y8_GPIO_NUM 11
#define Y7_GPIO_NUM 12
#define Y6_GPIO_NUM 14
#define Y5_GPIO_NUM 16
#define Y4_GPIO_NUM 18
#define Y3_GPIO_NUM 17
#define Y2_GPIO_NUM 15
#define VSYNC_GPIO_NUM 38
#define HREF_GPIO_NUM 47
#define PCLK_GPIO_NUM 13

static bool initCamera() {
  camera_config_t config;
  config.ledc_channel = LEDC_CHANNEL_0;
  config.ledc_timer = LEDC_TIMER_0;
  config.pin_d0 = Y2_GPIO_NUM;
  config.pin_d1 = Y3_GPIO_NUM;
  config.pin_d2 = Y4_GPIO_NUM;
  config.pin_d3 = Y5_GPIO_NUM;
  config.pin_d4 = Y6_GPIO_NUM;
  config.pin_d5 = Y7_GPIO_NUM;
  config.pin_d6 = Y8_GPIO_NUM;
  config.pin_d7 = Y9_GPIO_NUM;
  config.pin_xclk = XCLK_GPIO_NUM;
  config.pin_pclk = PCLK_GPIO_NUM;
  config.pin_vsync = VSYNC_GPIO_NUM;
  config.pin_href = HREF_GPIO_NUM;
  config.pin_sccb_sda = SIOD_GPIO_NUM;
  config.pin_sccb_scl = SIOC_GPIO_NUM;
  config.pin_pwdn = PWDN_GPIO_NUM;
  config.pin_reset = RESET_GPIO_NUM;
  config.xclk_freq_hz = 20000000;
  config.frame_size = FRAMESIZE_UXGA;
  config.pixel_format = PIXFORMAT_JPEG;
  config.grab_mode = CAMERA_GRAB_WHEN_EMPTY;
  config.fb_location = CAMERA_FB_IN_PSRAM;
  config.jpeg_quality = 12;
  config.fb_count = 1;

  if (config.pixel_format == PIXFORMAT_JPEG) {
    if (psramFound()) {
      config.jpeg_quality = 10;
      config.fb_count = 2;
      config.grab_mode = CAMERA_GRAB_LATEST;
    } else {
      config.frame_size = FRAMESIZE_SVGA;
      config.fb_location = CAMERA_FB_IN_DRAM;
    }
  }

  esp_err_t err = esp_camera_init(&config);
  if (err != ESP_OK) {
    Serial.printf("Camera init failed 0x%x\n", err);
    return false;
  }

  sensor_t *s = esp_camera_sensor_get();
  if (s->id.PID == OV3660_PID) {
    s->set_vflip(s, 1);
    s->set_brightness(s, 1);
    s->set_saturation(s, -2);
  }
  if (config.pixel_format == PIXFORMAT_JPEG) {
    s->set_framesize(s, FRAMESIZE_QVGA);
    s->set_quality(s, 14);
  }
  return true;
}

static void handleRoot() {
  const String ip = WiFi.localIP().toString();
  String html;
  html.reserve(1400);
  html += F("<!DOCTYPE html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width\">"
           "<title>XIAO CAM</title></head><body>");
  html += F("<h3>XIAO ESP32-S3 Sense</h3>");
  html += F("<p>Открой с телефона/ПК в <b>этой же Wi-Fi сети</b>:</p>");
  html += F("<p><b>http://");
  html += ip;
  html += F("/</b></p>");
  html += F("<p>Видео (MJPEG):</p>");
  html += F("<p><img src=\"/stream\" style=\"max-width:100%;height:auto;border:1px solid #0a0\"></p>");
  html += F("<p>Снимок:</p>");
  html += F("<p><img src=\"/capture\" style=\"max-width:100%;height:auto;border:1px solid #ccc\"></p>");
  html += F("<p><a href=\"/stream\">/stream</a> · <a href=\"/capture\">/capture</a></p>");
  html += F("</body></html>");
  server.send(200, "text/html; charset=utf-8", html);
}

static void handleStream() {
  WiFiClient client = server.client();
  if (!client || !client.connected()) {
    return;
  }

  const char *const boundary = "mjpeg";

  client.println(F("HTTP/1.1 200 OK"));
  client.println(F("Access-Control-Allow-Origin: *"));
  client.println(F("Connection: close"));
  client.print(F("Content-Type: multipart/x-mixed-replace; boundary="));
  client.println(boundary);
  client.println();

  while (client.connected()) {
    camera_fb_t *fb = esp_camera_fb_get();
    if (!fb) {
      delay(2);
      continue;
    }
    client.print(F("\r\n--"));
    client.print(boundary);
    client.print(F("\r\nContent-Type: image/jpeg\r\nContent-Length: "));
    client.print(fb->len);
    client.print(F("\r\n\r\n"));

    size_t remain = fb->len;
    uint8_t *p = fb->buf;
    while (remain > 0 && client.connected()) {
      const size_t chunk = remain > 4096 ? 4096 : remain;
      const size_t w = client.write(p, chunk);
      if (w == 0) {
        break;
      }
      p += w;
      remain -= w;
    }
    esp_camera_fb_return(fb);
    yield();
  }
}

static void handleCapture() {
  camera_fb_t *fb = esp_camera_fb_get();
  if (!fb) {
    server.send(500, "text/plain", "capture failed");
    return;
  }
  server.sendHeader("Cache-Control", "no-store");
  server.sendHeader("Access-Control-Allow-Origin", "*");
  server.setContentLength(fb->len);
  server.send(200, "image/jpeg", "");
  server.sendContent((const char *)fb->buf, fb->len);
  esp_camera_fb_return(fb);
}

void setup() {
  Serial.begin(115200);
  delay(800);

  if (!initCamera()) {
    Serial.println("Camera not ready — проверь Sense-плату, PSRAM=OPI в настройках платы, антенну.");
    return;
  }
  Serial.println("Camera OK");

  WiFi.mode(WIFI_STA);
  WiFi.setHostname("xiao-cam");
  WiFi.setSleep(false);
  WiFi.begin(kWifiSsid, kWifiPass);

  Serial.print(F("WiFi connecting to "));
  Serial.println(kWifiSsid);
  const uint32_t t0 = millis();
  while (WiFi.status() != WL_CONNECTED && millis() - t0 < kWifiTimeoutMs) {
    delay(500);
    Serial.print('.');
  }
  Serial.println();
  if (WiFi.status() != WL_CONNECTED) {
    Serial.println(F("WiFi: не удалось подключиться. Проверь SSID/пароль и сеть 2.4 ГГц."));
    return;
  }
  Serial.print(F("WiFi OK, IP: "));
  Serial.println(WiFi.localIP());

  server.on("/", HTTP_GET, handleRoot);
  server.on("/stream", HTTP_GET, handleStream);
  server.on("/capture", HTTP_GET, handleCapture);
  server.begin();
  Serial.println(F("HTTP server started (/) (/stream) (/capture)"));
}

void loop() {
  server.handleClient();
}

