#!/usr/bin/env python3
"""
Прокси XIAO CAM -> localhost (для браузера Cursor / Chrome: картинка с LAN не грузится со страницы 127.0.0.1).

Запуск (ПК в той же Wi-Fi, что и плата):
  py -3 tools/xiao_cam_proxy.py 192.168.1.50

Или впиши IP в файл camera_ip.txt в корне проекта (одна строка, без #).

Без IP прокси всё равно поднимается на 8898 — откроется подсказка (нет ERR_CONNECTION_REFUSED).

Открой: http://127.0.0.1:8898/
  Телеметрия в реальном времени: http://127.0.0.1:8898/telemetry
"""
from __future__ import annotations

import argparse
import http.client
import http.server
import json
import socketserver
import sys
from pathlib import Path


def load_ip_from_file(root: Path) -> str | None:
    p = root / "camera_ip.txt"
    if not p.is_file():
        return None
    for line in p.read_text(encoding="utf-8").splitlines():
        line = line.strip()
        if line and not line.startswith("#"):
            return line
    return None


def main() -> int:
    root = Path(__file__).resolve().parents[1]
    ap = argparse.ArgumentParser(description="XIAO CAM localhost proxy")
    ap.add_argument("camera_ip", nargs="?", help="IP платы в LAN")
    ap.add_argument("--port", type=int, default=8898)
    args = ap.parse_args()

    cam_ip: str | None = (args.camera_ip or "").strip() or load_ip_from_file(root)
    if not cam_ip:
        print(
            "IP не задан — слушаю 127.0.0.1:%d без проксирования на камеру. "
            "Добавь IP в camera_ip.txt или аргументом." % args.port,
            file=sys.stderr,
        )

    class Handler(http.server.BaseHTTPRequestHandler):
        protocol_version = "HTTP/1.1"

        def log_message(self, fmt, *a):
            sys.stderr.write("%s - %s\n" % (self.address_string(), fmt % a))

        def do_GET(self) -> None:  # noqa: N802
            path = self.path.split("?", 1)[0]
            if path == "/":
                self._home()
            elif path == "/telemetry":
                self._telemetry_dashboard()
            elif path == "/api/telemetry":
                self._api_telemetry()
            elif path == "/stream":
                self._stream_or_capture("/stream", stream=True)
            elif path == "/capture":
                self._stream_or_capture("/capture", stream=False)
            else:
                self.send_error(404)

        def _home(self) -> None:
            if cam_ip:
                self._video_page(cam_ip)
            else:
                self._need_ip_page()

        def _need_ip_page(self) -> None:
            txt = root / "camera_ip.txt"
            body = f"""<!DOCTYPE html>
<html lang="ru"><head><meta charset="utf-8"><title>XIAO прокси</title></head><body>
<h2>Прокси запущен, IP камеры не задан</h2>
<p>Создай файл <code>{txt}</code> одной строкой с IP (после <code>WiFi OK, IP:</code> в Serial 115200)
или запусти:</p>
<pre>py -3 tools\\xiao_cam_proxy.py 192.168.x.x</pre>
<p>Плата сейчас может быть в <code>error_wifi</code> — тогда в LAN нет адреса, сначала Wi‑Fi.</p>
<p><a href="/telemetry">телеметрия (режим без камеры)</a></p>
</body></html>"""
            data = body.encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Content-Length", str(len(data)))
            self.end_headers()
            self.wfile.write(data)

        def _video_page(self, ip: str) -> None:
            body = f"""<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>XIAO (proxy)</title></head><body>
<h3>Видео через прокси</h3>
<p>Камера: <code>{ip}</code></p>
<p><img src="/stream" style="max-width:100%;border:1px solid #080"></p>
<p><a href="/capture">один кадр</a> · <a href="/telemetry">телеметрия в реальном времени</a></p>
</body></html>"""
            data = body.encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Content-Length", str(len(data)))
            self.end_headers()
            self.wfile.write(data)

        def _api_telemetry(self) -> None:
            if not cam_ip:
                payload = {
                    "proxy_error": "no_camera_ip",
                    "hint": "Заполни camera_ip.txt или запусти прокси с аргументом IP. Плата в error_wifi не имеет LAN-IP.",
                    "camera_ip_txt": str(root / "camera_ip.txt"),
                }
                body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
                self.send_response(200)
                self.send_header("Content-Type", "application/json; charset=utf-8")
                self.send_header("Content-Length", str(len(body)))
                self.send_header("Cache-Control", "no-store")
                self.end_headers()
                self.wfile.write(body)
                return
            self._proxy("/telemetry", stream=False)

        def _stream_or_capture(self, cam_path: str, stream: bool) -> None:
            if not cam_ip:
                msg = b"no camera IP — set camera_ip.txt or run proxy with IP argument\r\n"
                self.send_response(503)
                self.send_header("Content-Type", "text/plain; charset=utf-8")
                self.send_header("Content-Length", str(len(msg)))
                self.end_headers()
                self.wfile.write(msg)
                return
            self._proxy(cam_path, stream=stream)

        def _telemetry_dashboard(self) -> None:
            label = cam_ip if cam_ip else "(IP не задан — см. / )"
            body = f"""<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>XIAO — телеметрия</title>
  <style>
    :root {{
      --bg: #0f1419;
      --panel: #1a2332;
      --text: #e6edf3;
      --muted: #8b949e;
      --accent: #58a6ff;
      --ok: #3fb950;
      --err: #f85149;
    }}
    body {{
      font-family: ui-sans-serif, system-ui, sans-serif;
      margin: 0;
      background: var(--bg);
      color: var(--text);
      min-height: 100vh;
    }}
    header {{
      padding: 12px 16px;
      background: var(--panel);
      border-bottom: 1px solid #30363d;
    }}
    h1 {{ font-size: 1.1rem; margin: 0 0 4px 0; }}
    .sub {{ color: var(--muted); font-size: 0.85rem; }}
    main {{ padding: 16px; display: grid; gap: 16px; grid-template-columns: 1fr; max-width: 960px; }}
    @media (min-width: 720px) {{
      main {{ grid-template-columns: 1fr 1fr; }}
    }}
    .card {{
      background: var(--panel);
      border-radius: 8px;
      padding: 12px 14px;
      border: 1px solid #30363d;
    }}
    .card h2 {{ font-size: 0.75rem; text-transform: uppercase; letter-spacing: 0.06em; color: var(--muted); margin: 0 0 10px 0; }}
    table {{ width: 100%; border-collapse: collapse; font-size: 0.85rem; font-variant-numeric: tabular-nums; }}
    td {{ padding: 4px 0; vertical-align: top; }}
    td:first-child {{ color: var(--muted); width: 42%; word-break: break-all; }}
    td:last-child {{ word-break: break-all; }}
    pre {{
      margin: 0;
      font-size: 0.72rem;
      line-height: 1.45;
      white-space: pre-wrap;
      word-break: break-all;
      max-height: 320px;
      overflow: auto;
      color: #c9d1d9;
    }}
    #status {{ font-size: 0.8rem; margin-top: 8px; }}
    #status.ok {{ color: var(--ok); }}
    #status.err {{ color: var(--err); }}
    a {{ color: var(--accent); }}
  </style>
</head>
<body>
