  String j;
  j.reserve(5600);
  j = '{';
  bool comma = false;

  esp_chip_info_t chip{};
  esp_chip_info(&chip);

  telemetryAppendUInt(j, comma, "uptime_ms", millis());
  telemetryAppendUInt(j, comma, "micros_lo", static_cast<uint32_t>(micros()));
