  telemetryAppendUInt(j, comma, "heap_max_block", ESP.getMaxAllocHeap());
  telemetryAppendUInt(j, comma, "heap_internal_free", heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT));
