#!/usr/bin/env python3
"""
Сбор телеметрии XIAO по USB (Serial): плата шлёт одну строку JSON на ~1.5 с (см. xiao_cam_stream.ino).

Закрой Serial Monitor в Arduino IDE / Cursor — COM-порт занят одним клиентом.

Примеры:
  py -3 tools/xiao_serial_telemetry.py --port COM5
  py -3 tools/xiao_serial_telemetry.py --port COM5 --log telemetry.ndjson
  py -3 tools/xiao_serial_telemetry.py --port COM5 --pretty
  py -3 tools/xiao_serial_telemetry.py --port COM5 --http 8897
    → http://127.0.0.1:8897/ в браузере (окно справа в Cursor: position=side)
"""
from __future__ import annotations

import argparse
import http.server
import json
import socketserver
import sys
import threading
from datetime import datetime, timezone
from pathlib import Path

LAST_USB: dict = {}
LAST_LOCK = threading.Lock()


def _dashboard_html(port: int, com: str) -> str:
    return f"""<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>XIAO — USB телеметрия</title>
  <style>
    :root {{
      --bg: #0f1419;
      --panel: #1a2332;
      --text: #e6edf3;
      --muted: #8b949e;
      --accent: #58a6ff;
      --ok: #3fb950;
      --err: #f85149;
    }}
    * {{ box-sizing: border-box; }}
    html, body {{ height: 100%; margin: 0; }}
    body {{
      font-family: ui-sans-serif, system-ui, sans-serif;
      background: var(--bg);
      color: var(--text);
      display: flex;
      flex-direction: column;
    }}
    header {{
      flex: 0 0 auto;
      padding: 10px 14px;
      background: var(--panel);
      border-bottom: 1px solid #30363d;
    }}
    h1 {{ font-size: 1.05rem; margin: 0 0 4px 0; }}
    .sub {{ color: var(--muted); font-size: 0.8rem; line-height: 1.35; }}
    #status {{ font-size: 0.78rem; margin-top: 6px; }}
    #status.ok {{ color: var(--ok); }}
    #status.err {{ color: var(--err); }}
    #scroll {{
      flex: 1 1 auto;
      overflow: auto;
      padding: 12px 14px 20px;
      max-width: 1100px;
      width: 100%;
      margin: 0 auto;
    }}
    #panels {{ display: flex; flex-direction: column; gap: 12px; }}
    .card {{
      background: var(--panel);
      border-radius: 8px;
      padding: 10px 12px;
      border: 1px solid #30363d;
    }}
    .card h2 {{
      font-size: 0.72rem;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      color: var(--accent);
      margin: 0 0 8px 0;
      font-weight: 600;
    }}
    table {{ width: 100%; border-collapse: collapse; font-size: 0.8rem; font-variant-numeric: tabular-nums; }}
    td {{ padding: 3px 6px 3px 0; vertical-align: top; border-bottom: 1px solid #252d3a; }}
    tr:last-child td {{ border-bottom: none; }}
    td.k {{ color: var(--muted); width: 38%; word-break: break-all; }}
    td.v {{ word-break: break-all; }}
    pre {{
      margin: 0;
      font-size: 0.68rem;
      line-height: 1.4;
      white-space: pre-wrap;
      word-break: break-all;
      max-height: min(38vh, 420px);
      overflow: auto;
      color: #c9d1d9;
    }}
  </style>
</head>
<body>
  <header>
    <h1>Телеметрия XIAO — USB Serial</h1>
    <div class="sub">Порт <code>{com}</code> · локальный сервер <code>127.0.0.1:{port}</code> ·
      опрос <code>/api/telemetry</code> каждые 0,5 с</div>
    <div id="status" class="ok">ожидание…</div>
  </header>
  <div id="scroll">
    <div id="panels"></div>
    <div class="card" style="margin-top:12px">
      <h2>Полный JSON</h2>
      <pre id="raw"></pre>
    </div>
  </div>
  <script>
    const elPanels = document.querySelector("#panels");
    const elRaw = document.querySelector("#raw");
    const elSt = document.querySelector("#status");

    const GROUP_ORDER = [
      "Прокси", "Система и MCU", "Память", "Flash и OTA", "Wi‑Fi",
      "Точка доступа (AP)", "Камера", "Датчики", "Прочее"
    ];

    function groupOf(k) {{
      if (k === "proxy_error" || k === "hint" || k === "camera_ip_txt") return "Прокси";
      if (k === "chip_temp_c") return "Датчики";
      if (k.startsWith("cam_")) return "Камера";
      if (k.startsWith("ap_")) return "Точка доступа (AP)";
      if (k.startsWith("wifi_")) return "Wi‑Fi";
      if (k.startsWith("part_") || k.startsWith("sketch_") || k.startsWith("flash_")) return "Flash и OTA";
      if (k.startsWith("heap_") || k.startsWith("psram_") || k.indexOf("stack") >= 0 || k.indexOf("rtos") >= 0 || k.indexOf("heap_ever") >= 0)
        return "Память";
      if (k.startsWith("uptime") || k.startsWith("micros") || k.startsWith("reset") || k.startsWith("led_") ||
          k.startsWith("chip_") || k.startsWith("cpu_") || k === "sdk" || k.startsWith("core_") ||
          k.startsWith("arduino") || k.startsWith("efuse"))
        return "Система и MCU";
      if (k === "usb" || k === "usb_error" || k === "_pc_ts") return "Прочее";
      return "Прочее";
    }}

    function esc(s) {{
      return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;");
    }}

    function fmtVal(v) {{
      if (v !== null && typeof v === "object") return JSON.stringify(v);
      return String(v);
    }}

    function render(obj) {{
      const buckets = {{}};
      GROUP_ORDER.forEach(function (g) {{ buckets[g] = []; }});
      Object.keys(obj).sort().forEach(function (k) {{
        const g = groupOf(k);
        if (!buckets[g]) buckets[g] = [];
        buckets[g].push({{ k: k, v: fmtVal(obj[k]) }});
      }});

      let html = "";
      GROUP_ORDER.forEach(function (g) {{
        const rows = buckets[g];
        if (!rows || !rows.length) return;
        html += '<section class="card"><h2>' + esc(g) + '</h2><table><tbody>';
        rows.forEach(function (r) {{
          html += '<tr><td class="k">' + esc(r.k) + '</td><td class="v">' + esc(r.v) + '</td></tr>';
        }});
        html += "</tbody></table></section>";
      }});
      elPanels.innerHTML = html;
      elRaw.textContent = JSON.stringify(obj, null, 2);
    }}

    async function tick() {{
      try {{
        const r = await fetch("/api/telemetry", {{ cache: "no-store" }});
        if (!r.ok) throw new Error("HTTP " + r.status);
        const j = await r.json();
        render(j);
        elSt.textContent = "обновлено " + new Date().toLocaleTimeString();
        elSt.className = "ok";
      }} catch (e) {{
        elSt.textContent = "ошибка: " + e;
        elSt.className = "err";
      }}
    }}
    tick();
    setInterval(tick, 500);
  </script>
</body>
</html>"""


def _serial_reader(port: str, baud: int, log_f) -> None:
    global LAST_USB
    import serial

    ser = serial.Serial(port, baud, timeout=0.3)
    buf = ""
    try:
        while True:
            chunk = ser.read(4096)
            if not chunk:
                continue
            buf += chunk.decode("utf-8", errors="replace")
            while "\n" in buf:
                line, buf = buf.split("\n", 1)
                line = line.strip()
                if not line or not line.startswith("{"):
                    continue
                try:
                    obj = json.loads(line)
                except json.JSONDecodeError:
                    continue
                ts = datetime.now(timezone.utc).isoformat()
                out = dict(obj)
                out["_pc_ts"] = ts
                with LAST_LOCK:
                    LAST_USB = out
                if log_f:
                    log_f.write(json.dumps(out, ensure_ascii=False) + "\n")
                    log_f.flush()
    finally:
        ser.close()


def _run_http_mode(port: str, baud: int, http_port: int, log_path: Path | None) -> int:
    import serial  # noqa: F401 — проверка импорта до потока

    log_f = log_path.open("a", encoding="utf-8") if log_path else None
    if log_f:
        log_f.write(
            "# http mode %s port=%s baud=%s http=%s\n"
            % (datetime.now(timezone.utc).isoformat(), port, baud, http_port)
        )
        log_f.flush()

    t = threading.Thread(target=_serial_reader, args=(port, baud, log_f), daemon=True)
    t.start()

    class H(http.server.BaseHTTPRequestHandler):
        protocol_version = "HTTP/1.1"

        def log_message(self, fmt, *args):
            sys.stderr.write("%s - %s\n" % (self.address_string(), fmt % args))

        def do_GET(self) -> None:
            path = self.path.split("?", 1)[0]
            if path == "/api/telemetry":
                with LAST_LOCK:
                    payload = dict(LAST_USB) if LAST_USB else {"usb": "waiting_for_first_json_line"}
                body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
                self.send_response(200)
                self.send_header("Content-Type", "application/json; charset=utf-8")
                self.send_header("Content-Length", str(len(body)))
                self.send_header("Cache-Control", "no-store")
                self.send_header("Access-Control-Allow-Origin", "*")
                self.end_headers()
                self.wfile.write(body)
            elif path == "/":
                html = _dashboard_html(http_port, port).encode("utf-8")
                self.send_response(200)
                self.send_header("Content-Type", "text/html; charset=utf-8")
                self.send_header("Content-Length", str(len(html)))
                self.send_header("Cache-Control", "no-store")
                self.end_headers()
                self.wfile.write(html)
            else:
                self.send_error(404)

    class Srv(socketserver.ThreadingMixIn, socketserver.TCPServer):
        allow_reuse_address = True
        daemon_threads = True

    print("USB → браузер: http://127.0.0.1:%d/" % http_port, file=sys.stderr)
    print("Serial %s @ %d (фон). Ctrl+C — остановить сервер." % (port, baud), file=sys.stderr)
    with Srv(("127.0.0.1", http_port), H) as httpd:
        try:
            httpd.serve_forever()
        except KeyboardInterrupt:
            print("\nОстанов.", file=sys.stderr)
    if log_f:
        log_f.close()
    return 0


def _run_console_mode(port: str, baud: int, log_path: Path | None, pretty: bool) -> int:
    import serial

    try:
        ser = serial.Serial(port, baud, timeout=0.3)
    except serial.SerialException as e:
        print("Не удалось открыть %s: %s" % (port, e), file=sys.stderr)
        return 1

    log_f = log_path.open("a", encoding="utf-8") if log_path else None
    if log_f:
        log_f.write("# started %s port=%s baud=%s\n" % (datetime.now(timezone.utc).isoformat(), port, baud))
        log_f.flush()

    print("Слушаю %s @ %d. Ctrl+C — выход." % (port, baud), file=sys.stderr)
    buf = ""

    try:
        while True:
            chunk = ser.read(4096)
            if not chunk:
                continue
            buf += chunk.decode("utf-8", errors="replace")
            while "\n" in buf:
                line, buf = buf.split("\n", 1)
                line = line.strip()
                if not line or not line.startswith("{"):
                    continue
                try:
                    obj = json.loads(line)
                except json.JSONDecodeError:
                    print("skip (not JSON):", line[:120], file=sys.stderr)
                    continue

                ts = datetime.now(timezone.utc).isoformat()
                if pretty:
                    print("--- %s ---" % ts)
                    print(json.dumps(obj, ensure_ascii=False, indent=2))
                else:
                    out = dict(obj)
                    out["_pc_ts"] = ts
                    print(json.dumps(out, ensure_ascii=False))

                if log_f:
                    rec = dict(obj)
                    rec["_pc_ts"] = ts
                    log_f.write(json.dumps(rec, ensure_ascii=False) + "\n")
                    log_f.flush()
    except KeyboardInterrupt:
        print("\nОстанов.", file=sys.stderr)
    finally:
        ser.close()
        if log_f:
            log_f.close()

    return 0


def main() -> int:
    ap = argparse.ArgumentParser(description="XIAO CAM telemetry over USB Serial")
    ap.add_argument("--port", default="COM5", help="Serial port (Windows: COM5, …)")
    ap.add_argument("--baud", type=int, default=115200)
    ap.add_argument(
        "--log",
        type=Path,
        metavar="FILE",
        help="Append each valid JSON line (NDJSON) with ISO timestamp",
    )
    ap.add_argument("--pretty", action="store_true", help="Pretty-print JSON to stdout (только без --http)")
    ap.add_argument(
        "--http",
        type=int,
        metavar="PORT",
        nargs="?",
        const=8897,
        help="Поднять http://127.0.0.1:PORT/ для окна браузера (по умолчанию 8897)",
    )
    args = ap.parse_args()

    try:
        import serial  # noqa: F401
    except ImportError:
        print("Нужен пакет pyserial: py -3 -m pip install pyserial", file=sys.stderr)
        return 2

    if args.http is not None:
        return _run_http_mode(args.port, args.baud, args.http, args.log)
    return _run_console_mode(args.port, args.baud, args.log, args.pretty)


if __name__ == "__main__":
    raise SystemExit(main())

