#Requires -Version 5.1
<#
.SYNOPSIS
  Найти XIAO ESP32-S3 по USB, прошить xiao_cam_stream (PSRAM=OPI), поднять телеметрию HTTP :8897.

.EXAMPLE
  .\tools\xiao_flash_and_telemetry.ps1
