package com.denzhogzhuy.xiaorobot

import android.graphics.Bitmap
import android.graphics.BitmapFactory
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import java.io.BufferedInputStream
import java.net.HttpURLConnection
import java.net.URL

/**
 * Читает MJPEG с http://host/stream (multipart/x-mixed-replace).
 */
class MjpegStream(
    private val scope: CoroutineScope,
    private val onFrame: (Bitmap) -> Unit,
    private val onStatus: (String) -> Unit,
) {
    private var job: Job? = null

    fun start(host: String) {
        stop()
        val url = "http://$host/stream"
        job = scope.launch(Dispatchers.IO) {
            onStatus("видео: подключение…")
            while (isActive) {
                var conn: HttpURLConnection? = null
                try {
                    conn = (URL(url).openConnection() as HttpURLConnection).apply {
                        connectTimeout = 8000
                        readTimeout = 0
                        requestMethod = "GET"
                    }
                    if (conn.responseCode != 200) {
                        onStatus("видео: HTTP ${conn.responseCode}")
                        kotlinx.coroutines.delay(1500)
                        continue
                    }
                    onStatus("видео: поток OK")
                    readLoop(BufferedInputStream(conn.inputStream))
                } catch (e: Exception) {
                    if (isActive) {
                        onStatus("видео: ${e.message}")
                        kotlinx.coroutines.delay(1200)
                    }
                } finally {
                    conn?.disconnect()
                }
            }
        }
    }

    fun stop() {
        job?.cancel()
        job = null
    }

    private fun readLoop(input: BufferedInputStream) {
        val buffer = ByteArray(256 * 1024)
        var acc = ByteArray(0)
        while (scope.coroutineContext.isActive) {
            val n = input.read(buffer)
            if (n <= 0) break
            acc = acc + buffer.copyOfRange(0, n)
            var soi = indexOf(acc, 0xFF, 0xD8)
            while (soi >= 0) {
                val eoi = indexOf(acc, 0xFF, 0xD9, soi + 2)
                if (eoi < 0) break
                val frame = acc.copyOfRange(soi, eoi + 2)
                val bmp = BitmapFactory.decodeByteArray(frame, 0, frame.size)
                if (bmp != null) {
                    scope.launch(Dispatchers.Main) { onFrame(bmp) }
                }
                acc = acc.copyOfRange(eoi + 2, acc.size)
                soi = indexOf(acc, 0xFF, 0xD8)
            }
            if (acc.size > 512 * 1024) {
                acc = ByteArray(0)
            }
        }
    }

    private fun indexOf(data: ByteArray, b0: Int, b1: Int, from: Int = 0): Int {
        var i = from
        while (i < data.size - 1) {
            if ((data[i].toInt() and 0xFF) == b0 && (data[i + 1].toInt() and 0xFF) == b1) {
                return i
            }
            i++
        }
        return -1
    }
}

package com.denzhogzhuy.xiaorobot

import android.media.AudioAttributes
import android.media.AudioFormat
import android.media.AudioTrack
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import java.io.BufferedInputStream
import java.net.Socket

/** PCM s16le mono 16 kHz с TCP :81 на плате. */
class MicPlayer(
    private val scope: CoroutineScope,
    private val onStatus: (String) -> Unit,
) {
    private var job: Job? = null
    private var track: AudioTrack? = null

    fun start(host: String) {
        stop()
        job = scope.launch(Dispatchers.IO) {
            onStatus("мик: подключение…")
            try {
                val socket = Socket(host, 81)
                socket.soTimeout = 500
                val minBuf = AudioTrack.getMinBufferSize(
                    16000,
                    AudioFormat.CHANNEL_OUT_MONO,
                    AudioFormat.ENCODING_PCM_16BIT,
                )
                val at = AudioTrack.Builder()
                    .setAudioAttributes(
                        AudioAttributes.Builder()
                            .setUsage(AudioAttributes.USAGE_MEDIA)
                            .setContentType(AudioAttributes.CONTENT_TYPE_SPEECH)
                            .build(),
                    )
                    .setAudioFormat(
                        AudioFormat.Builder()
                            .setSampleRate(16000)
                            .setEncoding(AudioFormat.ENCODING_PCM_16BIT)
                            .setChannelMask(AudioFormat.CHANNEL_OUT_MONO)
                            .build(),
                    )
                    .setBufferSizeInBytes(minBuf.coerceAtLeast(4096) * 4)
                    .setTransferMode(AudioTrack.MODE_STREAM)
                    .build()
                track = at
                at.play()
                onStatus("мик: воспроизведение")
                val inp = BufferedInputStream(socket.getInputStream())
                val buf = ByteArray(4096)
                while (isActive) {
                    val got = inp.read(buf)
                    if (got <= 0) break
                    at.write(buf, 0, got)
                }
                socket.close()
            } catch (e: Exception) {
                if (isActive) onStatus("мик: ${e.message}")
            } finally {
                track?.stop()
                track?.release()
                track = null
            }
        }
    }

    fun stop() {
        job?.cancel()
        job = null
        track?.stop()
        track?.release()
        track = null
    }
}

